from google.cloud import storage, firestore, pubsub_v1
from google.cloud.firestore_v1 import SERVER_TIMESTAMP
import base64
import json
import os
from cloudevents.http import CloudEvent

storage_client = storage.Client()
firestore_client = firestore.Client()
publisher = pubsub_v1.PublisherClient()

PROJECT_ID = os.environ.get("GCP_PROJECT") or os.environ.get("GOOGLE_CLOUD_PROJECT")
PUBSUB_TOPIC = os.environ.get("PUBSUB_TOPIC", "file-processed")


def process_gcs_file(cloud_event: CloudEvent):
    data = cloud_event.data
    bucket_name = data["bucket"]
    file_name = data["name"]
    generation = data.get("generation")
    content_type = data.get("contentType")
    size = int(data.get("size", 0))

    bucket = storage_client.bucket(bucket_name)
    blob = bucket.blob(file_name)
    content = blob.download_as_text()

    doc_ref = firestore_client.collection("processed_files").document()
    doc = {
        "bucket": bucket_name,
        "name": file_name,
        "generation": generation,
        "contentType": content_type,
        "size": size,
        "contentPreview": content[:1000],
        "processedAt": SERVER_TIMESTAMP,
    }
    doc_ref.set(doc)

    topic_path = publisher.topic_path(PROJECT_ID, PUBSUB_TOPIC)
    message = {
        "documentId": doc_ref.id,
        "bucket": bucket_name,
        "name": file_name,
        "generation": generation,
        "size": size,
    }
    publisher.publish(
        topic_path,
        json.dumps(message).encode("utf-8"),
        event_type="file_processed",
        source="gcs"
    ).result()

    return "OK"